const s=document.getElementById("main-nav");window.addEventListener("scroll",()=>{s?.classList.toggle("scrolled",window.scrollY>50)});const n=document.getElementById("navToggle"),o=document.getElementById("navLinks");n?.addEventListener("click",()=>{o?.classList.toggle("open"),n.classList.toggle("open")});const l=new IntersectionObserver(e=>{e.forEach(t=>{t.isIntersecting&&t.target.classList.add("visible")})},{threshold:.1});document.querySelectorAll(".reveal").forEach(e=>l.observe(e));
